using Service;

namespace Core.Save
{
    /// <summary>
    /// General-purpose persistence service backed by Unity PlayerPrefs.
    /// Register via ServiceLocator; inject into any system that needs persistence.
    /// </summary>
    public interface ISaveService : IService
    {
        /// <summary>Persists an integer value under the given key.</summary>
        void SaveInt(string key, int value);

        /// <summary>Reads an integer value; returns <paramref name="defaultValue"/> if not found.</summary>
        int LoadInt(string key, int defaultValue = 0);

        /// <summary>Persists a float value under the given key.</summary>
        void SaveFloat(string key, float value);

        /// <summary>Reads a float value; returns <paramref name="defaultValue"/> if not found.</summary>
        float LoadFloat(string key, float defaultValue = 0f);

        /// <summary>Persists a string value under the given key.</summary>
        void SaveString(string key, string value);

        /// <summary>Reads a string value; returns <paramref name="defaultValue"/> if not found.</summary>
        string LoadString(string key, string defaultValue = "");

        /// <summary>Returns true if the key exists in the save store.</summary>
        bool HasKey(string key);

        /// <summary>Removes a single key from the save store.</summary>
        void DeleteKey(string key);

        /// <summary>Wipes ALL saved data. Use with caution.</summary>
        void DeleteAll();

        /// <summary>Forces an immediate disk flush (wraps PlayerPrefs.Save).</summary>
        void Save();
    }
}

using System;
using System.Collections.Generic;
using Core.Enums;
using UnityEngine;

namespace Core.Save
{
    /// <summary>
    /// Designer-editable ScriptableObject that owns every PlayerPrefs key used by
    /// the game. Add a new <see cref="InventoryKeyEntry"/> row in the Inspector
    /// whenever a new collectable <see cref="TileType"/> is introduced – no code change needed.
    /// </summary>
    [CreateAssetMenu(fileName = "SaveData", menuName = "GameData/SaveData", order = 2)]
    public class SaveData : ScriptableObject
    {
        // ── Nested type ───────────────────────────────────────────────────────

        [Serializable]
        public struct InventoryKeyEntry
        {
            [Tooltip("The collectable tile type this key belongs to.")]
            public TileType tileType;

            [Tooltip("Unique PlayerPrefs key for this item's count. Must not be empty or duplicate.")]
            public string saveKey;
        }

        // ── Inspector fields ──────────────────────────────────────────────────

        [Header("Inventory Save Keys")]
        [Tooltip("Map every collectable TileType to a unique PlayerPrefs key.")]
        [SerializeField] private List<InventoryKeyEntry> inventoryKeys = new()
        {
            new InventoryKeyEntry { tileType = TileType.Strawberry, saveKey = "inventory_Strawberry" },
            new InventoryKeyEntry { tileType = TileType.Apple,      saveKey = "inventory_Apple"      },
            new InventoryKeyEntry { tileType = TileType.Pear,       saveKey = "inventory_Pear"       },
        };

        // ── Runtime cache ─────────────────────────────────────────────────────

        private Dictionary<TileType, string> _keyMap;

        // ── Public API ────────────────────────────────────────────────────────

        /// <summary>
        /// Returns the PlayerPrefs key for <paramref name="type"/>.
        /// Falls back to <c>"inventory_{type}"</c> if no entry is configured.
        /// </summary>
        public string GetInventoryKey(TileType type)
        {
            BuildMapIfNeeded();
            return _keyMap.TryGetValue(type, out var key) ? key : $"inventory_{type}";
        }

        /// <summary>
        /// Returns all <see cref="TileType"/> values that have a configured key.
        /// Used to iterate over known inventory entries at load-time.
        /// </summary>
        public IEnumerable<TileType> GetAllInventoryTypes()
        {
            BuildMapIfNeeded();
            return _keyMap.Keys;
        }

        // ── Helpers ───────────────────────────────────────────────────────────

        private void BuildMapIfNeeded()
        {
            if (_keyMap != null) return;

            _keyMap = new Dictionary<TileType, string>(inventoryKeys.Count);
            foreach (var entry in inventoryKeys)
            {
                if (entry.tileType == TileType.None || string.IsNullOrWhiteSpace(entry.saveKey))
                    continue;

                if (!_keyMap.TryAdd(entry.tileType, entry.saveKey))
                    Debug.LogWarning($"[SaveData] Duplicate entry for TileType '{entry.tileType}' – skipping.", this);
            }
        }

#if UNITY_EDITOR
        // Reset cache whenever the asset is edited in the Inspector.
        private void OnValidate() => _keyMap = null;
#endif
    }
}

using UnityEngine;

namespace Core.Save
{
    /// <summary>
    /// Concrete implementation of <see cref="ISaveService"/> using Unity PlayerPrefs.
    /// Pure C# class – no MonoBehaviour dependency.
    /// </summary>
    public class SaveService : ISaveService
    {
        // ── Int ──────────────────────────────────────────────────────────────
        public void SaveInt(string key, int value)   => PlayerPrefs.SetInt(key, value);
        public int  LoadInt(string key, int defaultValue = 0) => PlayerPrefs.GetInt(key, defaultValue);

        // ── Float ────────────────────────────────────────────────────────────
        public void  SaveFloat(string key, float value)            => PlayerPrefs.SetFloat(key, value);
        public float LoadFloat(string key, float defaultValue = 0f) => PlayerPrefs.GetFloat(key, defaultValue);

        // ── String ───────────────────────────────────────────────────────────
        public void   SaveString(string key, string value)               => PlayerPrefs.SetString(key, value);
        public string LoadString(string key, string defaultValue = "") => PlayerPrefs.GetString(key, defaultValue);

        // ── Utility ──────────────────────────────────────────────────────────
        public bool HasKey(string key)   => PlayerPrefs.HasKey(key);
        public void DeleteKey(string key) => PlayerPrefs.DeleteKey(key);
        public void DeleteAll()           => PlayerPrefs.DeleteAll();

        /// <summary>Forces an immediate write to disk.</summary>
        public void Save() => PlayerPrefs.Save();
    }
}
